describe('Navbar integration', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    mockPathname = '/';
    mockAuthState = {
      user: { email: 'ana@email.com', name: 'Ana', role: 'cliente' },
      logout: mockLogout,
    };
  });

  afterEach(() => {
    cleanup();
  });

  it('renders accessible primary navigation and item count labels', () => {
    render(<Navbar />);

    expect(screen.getByRole('navigation', { name: 'Navegación principal' })).toBeInTheDocument();

    // Desktop and mobile cart links can coexist in DOM; ensure at least one accessible match.
    expect(screen.getAllByRole('link', { name: 'Carrito, 2 productos' }).length).toBeGreaterThan(0);
    expect(screen.getByRole('link', { name: 'Favoritos, 1 productos' })).toBeInTheDocument();
    expect(screen.getByRole('combobox', { name: 'Idioma' })).toBeInTheDocument();
  });

  it('opens mobile menu and exposes navigation landmark with aria-expanded toggle', async () => {
    const user = userEvent.setup();
    render(<Navbar />);

    const toggleMenuButton = screen.getByRole('button', { name: 'Abrir menú' });
    expect(toggleMenuButton).toHaveAttribute('aria-expanded', 'false');

    await user.click(toggleMenuButton);

    expect(screen.getByRole('button', { name: 'Cerrar menú' })).toHaveAttribute('aria-expanded', 'true');
    expect(screen.getByRole('navigation', { name: 'Menú móvil' })).toBeInTheDocument();
  });

  it('logs out with broadcast notice and redirects to login', async () => {
    const user = userEvent.setup();
    render(<Navbar />);

    await user.click(screen.getByRole('button', { name: 'Cerrar sesión' }));

    expect(mockLogout).toHaveBeenCalledWith({
      broadcastNotice: {
        message: 'Tu sesión se cerró manualmente desde otra pestaña.',
        type: 'info',
        code: 'manual_logout',
      },
    });
    expect(mockNavigate).toHaveBeenCalledWith('/login', { replace: true });
  });
});
